// ═══════════════════════════════════════════════════════
//  spritesFase3.ts — Sprites da Fase 3 (Tempestade sobre São Burgão)
//
//  Zumbi Flatulento (comum), Zumbi Turbinado (raro),
//  Suka Mark II (boss) + Props do cenário
//
//  COMO ADICIONAR UM SPRITE:
//  1. Cole o base64 entre as aspas do campo correspondente.
//     Formato: 'data:image/png;base64,iVBOR...'
//  2. Tamanho recomendado: 120x120px (inimigos) / 80x80px (props)
//  3. O pré-carregamento é automático via preloadFase3Sprites().
// ═══════════════════════════════════════════════════════

// ─────────────────────────────────────────────────────
//  SPRITES DE INIMIGOS
// ─────────────────────────────────────────────────────

export const FASE3_SPRITES = {

    // ── ZUMBI FLATULENTO (inimigo comum) ──────────────
    zumbi_parado:       'data:image/png;base64,',  // Idle: curvado, braços caídos, gás saindo
    zumbi_andando1:     'data:image/png;base64,',  // Walk 1: pé esquerdo arrastando
    zumbi_andando2:     'data:image/png;base64,',  // Walk 2: pé direito arrastando
    zumbi_gas:          'data:image/png;base64,',  // Gás: nuvem enorme colorida explodindo
    zumbi_dano:         'data:image/png;base64,',  // Dano: jogado pra trás, impacto
    zumbi_regenerando:  'data:image/png;base64,',  // Regen: aura verde brilhante
  
    // ── ZUMBI TURBINADO (variante rara) ───────────────
    zumbi_turbo_parado:       'data:image/png;base64,',  // Idle: imponente, gás denso, veias brilhando
    zumbi_turbo_andando1:     'data:image/png;base64,',  // Walk 1: pisada pesada esquerda
    zumbi_turbo_andando2:     'data:image/png;base64,',  // Walk 2: pisada pesada direita
    zumbi_turbo_gas:          'data:image/png;base64,',  // Gás: corpo inflado, nuvem ENORME
    zumbi_turbo_dano:         'data:image/png;base64,',  // Dano: mal recua, tanque
    zumbi_turbo_regenerando:  'data:image/png;base64,',  // Regen: brilho verde intenso
  
    // ── SUKA MARK II (Boss Fase 3) ────────────────────
    //  Fases: 100-50% HP → melee+grito | 50-25% → voo | 25-0% → falha
    suka_mk2_parada:          'data:image/png;base64,',  // Idle: confiante, espada ao lado
    suka_mk2_andando1:        'data:image/png;base64,',  // Walk 1: passo blindado esquerdo
    suka_mk2_andando2:        'data:image/png;base64,',  // Walk 2: passo blindado direito
    suka_mk2_espada:          'data:image/png;base64,',  // Espada: golpe horizontal, rastro roxo
    suka_mk2_grito:           'data:image/png;base64,',  // Grito: ondas sônicas saindo da boca
    suka_mk2_escudo:          'data:image/png;base64,',  // Escudo: bolha de energia roxa
    suka_mk2_contra_ataque:   'data:image/png;base64,',  // Contra: descarga elétrica em todas direções
    suka_mk2_voando:          'data:image/png;base64,',  // Voo: propulsores acesos, pernas recolhidas
    suka_mk2_mergulho:        'data:image/png;base64,',  // Mergulho: diagonal, espada à frente
    suka_mk2_falhando:        'data:image/png;base64,',  // Falha: armadura rachada, faíscas
  
  } as const;
  
  // ─────────────────────────────────────────────────────
  //  SPRITES DOS PROPS DO CENÁRIO
  //  (usados pelo EnvObjectComp no PhaseRenderer)
  //
  //  Referência visual: sprite sheet horizontal enviada
  //  Ordem: botijão | carrinho | poste | placa | botijão_explodindo
  // ─────────────────────────────────────────────────────
  
  export const FASE3_PROP_SPRITES = {
    botijao_intacto:     'data:image/png;base64,',  // Botijão vermelho fechado (col 1 do sheet)
    botijao_explodindo:  'data:image/png;base64,',  // Botijão com fogo (col 5 do sheet)
    carrinho_intacto:    'data:image/png;base64,',  // Carrinho de fritura com óleo (col 2)
    carrinho_tombado:    'data:image/png;base64,',  // Carrinho virado (estado após hit)
    poste_intacto:       'data:image/png;base64,',  // Poste de luz aceso (col 3)
    poste_caido:         'data:image/png;base64,',  // Poste caído no chão (estado após combo)
    placa_intacta:       'data:image/png;base64,',  // Placa de lanchonete com hambúrguer (col 4)
    placa_voando:        'data:image/png;base64,',  // Placa em movimento (estado após bufa)
  } as const;
  
  // ─────────────────────────────────────────────────────
  //  CENÁRIO
  // ─────────────────────────────────────────────────────
  
  export const CENARIO_FASE3 = "data:image/jpeg;base64,";
  
  // ─────────────────────────────────────────────────────
  //  PRÉ-CARREGAMENTO
  //  Chame preloadFase3Sprites() no início da Fase3.tsx
  //  para evitar flash no primeiro frame.
  // ─────────────────────────────────────────────────────
  
  const _cache = new Map<string, HTMLImageElement>();
  
  export function preloadFase3Sprites(): Promise<void[]> {
    const allSprites = [
      ...Object.values(FASE3_SPRITES),
      ...Object.values(FASE3_PROP_SPRITES),
      CENARIO_FASE3,
    ].filter(Boolean); // ignora strings vazias
  
    return Promise.all(
      allSprites.map(
        src =>
          new Promise<void>((resolve) => {
            if (_cache.has(src)) { resolve(); return; }
            const img = new Image();
            img.onload = () => { _cache.set(src, img); resolve(); };
            img.onerror = () => resolve(); // falha silenciosa — cai no fallback CSS
            img.src = src;
          }),
      ),
    );
  }
  
  /** Retorna a imagem em cache (ou undefined se ainda não carregada / vazia) */
  export function getCachedSprite(src: string): HTMLImageElement | undefined {
    return _cache.get(src);
  }
  
  // ─────────────────────────────────────────────────────
  //  SELETOR DE POSE
  //  Retorna o base64 correto dado o estado atual do inimigo.
  //  Compatível com Enemy.type === 'zumbi' | 'zumbi_turbo' | 'suka_mk2'
  // ─────────────────────────────────────────────────────
  
  import type { Enemy } from './types';
  
  export function getZumbiSprite(e: Enemy, frame: number): string {
    const walk = frame % 20 < 10 ? 'zumbi_andando1' : 'zumbi_andando2';
  
    if (e.hurt)                              return FASE3_SPRITES.zumbi_dano;
    if (e.regenTimer !== undefined
      && e.regenTimer > 0 && e.hp < 3)       return FASE3_SPRITES.zumbi_regenerando;
    if (e.gasTimer !== undefined
      && e.gasTimer > 0)                     return FASE3_SPRITES.zumbi_gas;
    if (e.walking)                           return FASE3_SPRITES[walk];
    return FASE3_SPRITES.zumbi_parado;
  }
  
  export function getZumbiTurboSprite(e: Enemy, frame: number): string {
    const walk = frame % 16 < 8 ? 'zumbi_turbo_andando1' : 'zumbi_turbo_andando2';
  
    if (e.hurt)                              return FASE3_SPRITES.zumbi_turbo_dano;
    if (e.regenTimer !== undefined
      && e.regenTimer > 0 && e.hp < 8)       return FASE3_SPRITES.zumbi_turbo_regenerando;
    if (e.gasTimer !== undefined
      && e.gasTimer > 0)                     return FASE3_SPRITES.zumbi_turbo_gas;
    if (e.walking)                           return FASE3_SPRITES[walk];
    return FASE3_SPRITES.zumbi_turbo_parado;
  }
  
  export function getSukaMK2Sprite(e: Enemy, frame: number): string {
    const walk = frame % 18 < 9 ? 'suka_mk2_andando1' : 'suka_mk2_andando2';
    const hpPct = e.hp / e.maxHp;
  
    if (e.hurt)            return FASE3_SPRITES.suka_mk2_falhando;
    if (e.armorFailing)    return FASE3_SPRITES.suka_mk2_falhando;
    if (e.flying)          return e.charging
                             ? FASE3_SPRITES.suka_mk2_mergulho
                             : FASE3_SPRITES.suka_mk2_voando;
    if (e.absorbing)       return FASE3_SPRITES.suka_mk2_escudo;
    if (e.charging)        return FASE3_SPRITES.suka_mk2_contra_ataque;
    if (e.punchTimer > 10) return hpPct > 0.5
                             ? FASE3_SPRITES.suka_mk2_espada
                             : FASE3_SPRITES.suka_mk2_grito;
    if (e.walking)         return FASE3_SPRITES[walk];
    return FASE3_SPRITES.suka_mk2_parada;
  }
  
  /** Entry point unificado — use nos componentes de render */
  export function getFase3EnemySprite(e: Enemy, frame: number): string {
    if (e.type === 'zumbi')       return getZumbiSprite(e, frame);
    if (e.type === 'zumbi_turbo') return getZumbiTurboSprite(e, frame);
    if (e.type === 'suka_mk2')    return getSukaMK2Sprite(e, frame);
    return '';
  }
  
  // ─────────────────────────────────────────────────────
  //  SELETOR DE PROP DO CENÁRIO
  //  Retorna o base64 correto para o estado do EnvironmentObject.
  // ─────────────────────────────────────────────────────
  
  import type { EnvironmentObject } from './types';
  
  export function getFase3PropSprite(obj: EnvironmentObject): string {
    switch (obj.type) {
      case 'botijao':
        return obj.exploding
          ? FASE3_PROP_SPRITES.botijao_explodindo
          : FASE3_PROP_SPRITES.botijao_intacto;
  
      case 'carrinho':
        return !obj.active
          ? FASE3_PROP_SPRITES.carrinho_tombado
          : FASE3_PROP_SPRITES.carrinho_intacto;
  
      case 'poste':
        return !obj.active
          ? FASE3_PROP_SPRITES.poste_caido
          : FASE3_PROP_SPRITES.poste_intacto;
  
      case 'placa':
        return Math.abs(obj.vx) > 0.5
          ? FASE3_PROP_SPRITES.placa_voando
          : FASE3_PROP_SPRITES.placa_intacta;
  
      default:
        return '';
    }
  }
  